public String repeatEnd(String str, int n) {
    if(n == 0) {
        return "";
    } else {
        int len = str.length();
        String endSubstring = str.substring(len - n);
        StringBuilder result = new StringBuilder();

        for(int i = 0; i < n; i++) {
            result.append(endSubstring);
        }

        return result.toString();
    }
}

